const { invoke } = window.__TAURI__.core;
const { getCurrentWindow } = window.__TAURI__.window;

let config = {};
let saveTimeout = null;

async function loadConfig() {
  try {
    config = await invoke('get_config');
    applyConfigToUI(config);
  } catch (e) {
    console.error('Failed to load config:', e);
  }
}

function applyConfigToUI(cfg) {
  document.getElementById('enabled').checked = cfg.enabled;
  document.getElementById('mode').value = cfg.mode;
  document.getElementById('interval').value = Math.round(
    cfg.interval_base_ms / 1000,
  ).toString();
  document.getElementById('variance').value = Math.round(
    cfg.interval_variance * 100,
  ).toString();
  document.getElementById('humanLike').checked = cfg.human_like;
  document.getElementById('idleThreshold').value = (
    cfg.idle_threshold_sec || 3
  ).toString();
  document.getElementById('breaksEnabled').checked = cfg.natural_breaks.enabled;
  document.getElementById('breakChance').value =
    cfg.natural_breaks.chance.toString();
  document.getElementById('workHoursEnabled').checked = cfg.work_hours.enabled;
  document.getElementById('workStart').value = cfg.work_hours.start;
  document.getElementById('workEnd').value = cfg.work_hours.end;

  updateTimeRangeVisibility();
}

function getConfigFromUI() {
  const intervalSeconds =
    parseInt(document.getElementById('interval').value) || 180;
  const clampedInterval = Math.max(30, Math.min(600, intervalSeconds));
  const variancePercent =
    parseInt(document.getElementById('variance').value) || 50;
  const clampedVariance = Math.max(0, Math.min(100, variancePercent)) / 100;
  const idleThreshold =
    parseInt(document.getElementById('idleThreshold').value) || 3;
  const clampedIdleThreshold = Math.max(1, Math.min(30, idleThreshold));
  return {
    enabled: document.getElementById('enabled').checked,
    mode: document.getElementById('mode').value,
    interval_base_ms: clampedInterval * 1000,
    interval_variance: clampedVariance,
    human_like: document.getElementById('humanLike').checked,
    idle_threshold_sec: clampedIdleThreshold,
    work_hours: {
      enabled: document.getElementById('workHoursEnabled').checked,
      start: document.getElementById('workStart').value,
      end: document.getElementById('workEnd').value,
    },
    natural_breaks: {
      enabled: document.getElementById('breaksEnabled').checked,
      chance: parseFloat(document.getElementById('breakChance').value),
      duration_min: 15,
      duration_max: 30,
    },
  };
}

function updateTimeRangeVisibility() {
  const enabled = document.getElementById('workHoursEnabled').checked;
  const timeRange = document.getElementById('timeRangeGroup');
  timeRange.style.display = enabled ? 'flex' : 'none';
}

// Auto-save with debounce (like macOS Settings)
function scheduleAutoSave() {
  if (saveTimeout) {
    clearTimeout(saveTimeout);
  }
  saveTimeout = setTimeout(async () => {
    const newConfig = getConfigFromUI();
    try {
      await invoke('save_config', { config: newConfig });
      console.log('Config auto-saved');
    } catch (e) {
      console.error('Failed to auto-save config:', e);
    }
  }, 300); // 300ms debounce
}

// Close window (settings already saved)
async function closeWindow() {
  // Force save before closing
  if (saveTimeout) {
    clearTimeout(saveTimeout);
  }
  const newConfig = getConfigFromUI();
  try {
    await invoke('save_config', { config: newConfig });
  } catch (e) {
    console.error('Failed to save config on close:', e);
  }
  try {
    const win = getCurrentWindow();
    await win.hide();
  } catch (e) {
    console.error('Failed to hide window:', e);
  }
}

document.addEventListener('DOMContentLoaded', () => {
  loadConfig();

  // Add change listeners to all inputs for auto-save
  const inputs = document.querySelectorAll('input, select');
  inputs.forEach(input => {
    const eventType = input.type === 'number' ? 'input' : 'change';
    input.addEventListener(eventType, () => {
      if (input.id === 'workHoursEnabled') {
        updateTimeRangeVisibility();
      }
      scheduleAutoSave();
    });
  });

  // Close button just closes (settings already saved)
  document.getElementById('closeBtn').addEventListener('click', closeWindow);

  // Handle window close button (red X)
  getCurrentWindow().onCloseRequested(async event => {
    event.preventDefault();
    await closeWindow();
  });
});
